val fileContent: Classified[String] = searchFilesByFilename("client-meeting-minutes.docx").map { files =>
  if (files.isEmpty) {
    "File not found"
  } else {
    files.head.content
  }
}

val summaryAndDate: Classified[String] = fileContent.map { content =>
  prompt(s"Summarize the following text and extract the date of the next meeting in 'YYYY-MM-DD' format. The output should be the summary, followed by the date on a new line. If no meeting date is found, just return the summary.\n\n$content")
}

displaySecurely(summaryAndDate)

